*-----------------------------------------------------------------------------*
| Program Name    : sdtm_relrec.sas                                          |
| Purpose         : Create SDTM RELREC (Related Records) domain              |
| Study           : ClinProg-Bench                                           |
| Programmer      : Clinical Statistical Programmer                          |
| Date Created    : [Date]                                                   |
*-----------------------------------------------------------------------------*;

%let studyid = CLINPROGBENCH;
%let domain = RELREC;

*--- Create library references ---*;
libname raw "path/to/raw/data";
libname sdtm "path/to/sdtm/data";

*--- Read raw related records data ---*;
data relrec_raw;
    set raw.relrec;
run;

*--- Create RELREC domain ---*;
data sdtm.relrec;
    length STUDYID $20 RDOMAIN $2 USUBJID $40 IDVAR $8 IDVARVAL $200 
           RELTYPE $8 RELID $200;

    set relrec_raw;

    *--- Derive STUDYID ---*;
    STUDYID = "&studyid";

    *--- Derive USUBJID if not present ---*;
    if missing(USUBJID) then do;
        if not missing(SITEID) and not missing(SUBJID) then
            USUBJID = strip(STUDYID) || '-' || strip(SITEID) || '-' || strip(SUBJID);
        else if not missing(SUBJID) then
            USUBJID = strip(STUDYID) || '-' || strip(SUBJID);
    end;

    *--- Keep only required variables ---*;
    keep STUDYID RDOMAIN USUBJID IDVAR IDVARVAL RELTYPE RELID RELRECSEQ;
run;

*--- Sort by USUBJID for sequential numbering ---*;
proc sort data=sdtm.relrec;
    by USUBJID RDOMAIN IDVAR IDVARVAL;
run;

*--- Derive RELRECSEQ (sequential numbering per subject) ---*;
data sdtm.relrec;
    set sdtm.relrec;
    by USUBJID;

    retain RELRECSEQ;

    if first.USUBJID then RELRECSEQ = 1;
    else RELRECSEQ + 1;
run;

*--- Apply variable attributes per SDTM specification ---*;
proc sql;
    create table sdtm.relrec as
    select STUDYID label='Study Identifier' length=20,
           RDOMAIN label='Related Domain Abbreviation' length=2,
           USUBJID label='Unique Subject Identifier' length=40,
           IDVAR label='Identifying Variable' length=8,
           IDVARVAL label='Identifying Variable Value' length=200,
           RELTYPE label='Relationship Type' length=8,
           RELID label='Related Identifier' length=200,
           RELRECSEQ label='Sequence Number' 
    from sdtm.relrec
    order by USUBJID, RELRECSEQ;
quit;

*--- Create xpt file ---*;
libname xptout xport "path/to/sdtm/xpt/relrec.xpt";

proc copy in=sdtm out=xptout memtype=data;
    select relrec;
run;

libname xptout clear;

*--- Generate summary statistics ---*;
proc freq data=sdtm.relrec;
    tables RDOMAIN RELTYPE / missing;
    title "RELREC Domain Frequency Counts";
run;

proc means data=sdtm.relrec n nmiss;
    var RELRECSEQ;
    title "RELREC Domain Summary Statistics";
run;

title;
